import React, { useState, useRef } from 'react';

interface GlassCardProps {
  children: React.ReactNode;
  className?: string;
  isHoverable?: boolean;
}

export const GlassCard: React.FC<GlassCardProps> = ({ children, className = "", isHoverable = true }) => {
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [opacity, setOpacity] = useState(0);
  const cardRef = useRef<HTMLDivElement>(null);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;

    const div = cardRef.current;
    const rect = div.getBoundingClientRect();

    setPosition({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  const handleMouseEnter = () => setOpacity(1);
  const handleMouseLeave = () => setOpacity(0);

  return (
    <div
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      className={`
        relative overflow-hidden
        bg-white/[0.03] backdrop-blur-xl
        border border-white/[0.08]
        rounded-2xl
        p-6 md:p-8
        transition-all duration-500
        ${isHoverable ? 'hover:bg-white/[0.06] hover:border-white/[0.15] hover:-translate-y-1' : ''}
        ${className}
      `}
    >
      {/* Spotlight effect */}
      <div
        className="pointer-events-none absolute -inset-px transition duration-300"
        style={{
          opacity,
          background: `radial-gradient(600px circle at ${position.x}px ${position.y}px, rgba(236, 72, 153, 0.1), transparent 40%)`,
        }}
      />

      {/* Subtle inner glow */}
      <div className="absolute inset-0 bg-gradient-to-br from-white/[0.02] to-transparent pointer-events-none" />

      <div className="relative z-10">
        {children}
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';

export const SignalVisualizer: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [noiseLevel, setNoiseLevel] = useState(0.5);
  const [isProcessing, setIsProcessing] = useState(true);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let offset = 0;

    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const width = canvas.width;
      const height = canvas.height;
      const centerY = height / 2;

      // Draw Grid
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
      ctx.lineWidth = 1;
      for (let i = 0; i < width; i += 40) {
        ctx.beginPath();
        ctx.moveTo(i, 0);
        ctx.lineTo(i, height);
        ctx.stroke();
      }
      for (let j = 0; j < height; j += 40) {
        ctx.beginPath();
        ctx.moveTo(0, j);
        ctx.lineTo(width, j);
        ctx.stroke();
      }

      // Draw Base Signal (Sine)
      ctx.beginPath();
      ctx.lineWidth = 2;
      ctx.strokeStyle = isProcessing ? 'rgba(236, 72, 153, 0.8)' : 'rgba(236, 72, 153, 0.2)';

      for (let x = 0; x < width; x++) {
        const y = centerY + Math.sin((x + offset) * 0.02) * 50;
        // Add interactive noise
        const currentNoise = (Math.random() - 0.5) * 100 * noiseLevel;
        if (x === 0) ctx.moveTo(x, y + currentNoise);
        else ctx.lineTo(x, y + currentNoise);
      }
      ctx.stroke();

      // Draw "Cleaned" Signal if processing
      if (isProcessing && noiseLevel > 0) {
        ctx.beginPath();
        ctx.lineWidth = 3;
        ctx.strokeStyle = '#818cf8';
        ctx.setLineDash([5, 5]);
        for (let x = 0; x < width; x++) {
          const y = centerY + Math.sin((x + offset) * 0.02) * 50;
          if (x === 0) ctx.moveTo(x, y);
          else ctx.lineTo(x, y);
        }
        ctx.stroke();
        ctx.setLineDash([]);
      }

      offset += 2;
      animationFrameId = window.requestAnimationFrame(render);
    };

    render();
    return () => window.cancelAnimationFrame(animationFrameId);
  }, [noiseLevel, isProcessing]);

  return (
    <div className="flex flex-col gap-4">
      <div className="relative rounded-xl overflow-hidden bg-black/40 border border-white/10 aspect-[21/9] md:aspect-[4/1]">
        <canvas 
          ref={canvasRef} 
          width={800} 
          height={200} 
          className="w-full h-full"
        />
        <div className="absolute top-4 right-4 flex items-center gap-2">
           <span className="text-[10px] font-mono text-white/40 uppercase tracking-widest">Signal Status:</span>
           <span className={`text-[10px] font-mono px-2 py-0.5 rounded border ${isProcessing ? 'border-pink-500/50 text-pink-400 bg-pink-500/10' : 'border-white/20 text-white/40'}`}>
             {isProcessing ? 'MODEL_ACTIVE' : 'RAW_FEED'}
           </span>
        </div>
      </div>
      <div className="flex flex-col sm:flex-row items-center justify-between gap-6 px-2">
        <div className="flex items-center gap-4 w-full sm:w-auto">
          <label className="text-xs font-mono text-white/60 uppercase tracking-tighter">Entropy Level</label>
          <input 
            type="range" 
            min="0" 
            max="1" 
            step="0.01" 
            value={noiseLevel} 
            onChange={(e) => setNoiseLevel(parseFloat(e.target.value))}
            className="w-full sm:w-48 accent-pink-500 h-1 bg-white/10 rounded-lg appearance-none cursor-pointer"
          />
        </div>
        <button 
          onClick={() => setIsProcessing(!isProcessing)}
          className={`px-4 py-2 rounded-lg text-xs font-mono border transition-all ${isProcessing ? 'bg-indigo-500/20 border-indigo-500/50 text-indigo-300' : 'bg-white/5 border-white/10 text-white/40 hover:text-white'}`}
        >
          {isProcessing ? 'STOP SIGNAL FILTER' : 'START SIGNAL FILTER'}
        </button>
      </div>
    </div>
  );
};

