        <div className="absolute top-[10%] left-[10%] w-[40rem] h-[40rem] bg-indigo-500/10 rounded-full blur-[120px]" />
        <div className="absolute bottom-[10%] right-[10%] w-[30rem] h-[30rem] bg-pink-500/10 rounded-full blur-[120px]" />

        {/* Animated Grid */}
        <div className="absolute inset-0 bg-[linear-gradient(to_right,#ffffff05_1px,transparent_1px),linear-gradient(to_bottom,#ffffff05_1px,transparent_1px)] bg-[size:40px_40px] [mask-image:radial-gradient(ellipse_60%_50%_at_50%_0%,#000_70%,transparent_100%)]" />
      </div>

      {/* Navigation */}
      <nav className="fixed top-0 left-0 w-full z-40 px-6 py-6 flex justify-between items-center backdrop-blur-md bg-black/20 border-b border-white/5">
        <div 
          className="text-xl font-bold tracking-tighter flex items-center gap-2 group cursor-pointer" 
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
        >
          <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-pink-500 to-purple-600 flex items-center justify-center transition-transform group-hover:scale-110">
            <span className="text-white">D</span>
          </div>
          <span className="bg-clip-text text-transparent bg-gradient-to-r from-white to-white/60">Bansode</span>
        </div>
        <div className="flex gap-4 md:gap-8 text-sm font-medium">
          {[
            { id: 'about', label: 'About' },
            { id: 'experience', label: 'Experience' },
            { id: 'projects', label: 'Projects' },
            { id: 'skills', label: 'Expertise' }
          ].map((nav) => (
            <button 
              key={nav.id}
              onClick={() => scrollToSection(nav.id)} 
              className={`transition-all cursor-pointer relative py-1 ${activeSection === nav.id ? 'text-pink-400' : 'text-white/40 hover:text-white'}`}
            >
              {nav.label}
              {activeSection === nav.id && (
                <span className="absolute bottom-0 left-0 w-full h-px bg-pink-500 animate-in fade-in slide-in-from-left-2 duration-300" />
